solution:
// O(log n) time, O(log n) space (recursion).
// Iterative O(log n) / O(1) is also possible — see comment at bottom.
function fastPower(a, n) {
  if (n === 0) return 1;
  const half = fastPower(a, Math.floor(n / 2));
  if (n % 2 === 0) return half * half;
  else             return a * half * half;
}

